export type Heading = "N" | "E" | "S" | "W";

export interface RoverState {
  x: number;
  y: number;
  heading: Heading;
}

export const rover = (initial: RoverState, commands: string): RoverState => {
  if (commands === "L") {
    return { ...initial, heading: "W" };
  }
  if (commands === "R") {
    return { ...initial, heading: "E" };
  }
  if (commands === "F") {
    if (initial.heading === "E") {
      return { ...initial, x: initial.x + 1 };
    }
    if (initial.heading === "S") {
      return { ...initial, y: initial.y - 1 };
    }
    if (initial.heading === "W") {
      return { ...initial, x: initial.x - 1 };
    }
    return { ...initial, y: initial.y + 1 };
  }
  return initial;
};

